Here's a minimal API endpoint handling multipart form uploads with multiple images and a description field:

```csharp
using Microsoft.AspNetCore.Http.Features;

var builder = WebApplication.CreateBuilder(args);

// Increase the max request body size to 50MB
builder.WebHost.ConfigureKestrel(options =>
{
    options.Limits.MaxRequestBodySize = 50 * 1024 * 1024;
});

var app = builder.Build();

app.MapPost("/upload", async (HttpRequest request) =>
{
    // Ensure it's a multipart form request
    if (!request.HasFormContentType)
        return Results.BadRequest("Expected a multipart/form-data request.");

    var form = await request.ReadFormAsync();
    var description = form["description"].ToString();
    var files = form.Files.GetFiles("images");

    if (files.Count == 0)
        return Results.BadRequest("No image files provided.");

    var allowedTypes = new[] { "image/jpeg", "image/png", "image/gif", "image/webp" };
    var savedFiles = new List<string>();

    foreach (var file in files)
    {
        if (!allowedTypes.Contains(file.ContentType))
            return Results.BadRequest($"Invalid content type: {file.ContentType}");

        var fileName = $"{Guid.NewGuid()}{Path.GetExtension(file.FileName)}";
        var savePath = Path.Combine("uploads", fileName);
        Directory.CreateDirectory("uploads");

        await using var stream = File.Create(savePath);
        await file.CopyToAsync(stream);
        savedFiles.Add(fileName);
    }

    return Results.Ok(new { description, uploadedFiles = savedFiles });
})
.DisableAntiforgery() // Required for minimal APIs accepting form data without tokens
.WithRequestFormLimits(multipartBodyLengthLimit: 50 * 1024 * 1024);

app.Run();
```

**Key points:**

- `ConfigureKestrel` raises the request body limit (default is ~30MB).
- `.WithRequestFormLimits(...)` sets the multipart-specific limit to match.
- `.DisableAntiforgery()` is needed since minimal APIs enforce antiforgery on form endpoints by default (.NET 8+).
- Files are read from the form via `GetFiles("images")` matching the field name in the submitted form.

**Example `curl` to test:**

```bash
curl -X POST http://localhost:5000/upload \
  -F "description=My vacation photos" \
  -F "images=@photo1.jpg" \
  -F "images=@photo2.png"
```
